+    #[test]
+    fn aggregated_series_trim_empty_is_noop() {
+        let mut series = AggregatedTimeSeries::new(Granularity::OneSecond, 1);
+        series.trim_to_window(Duration::from_secs(10));
+        assert!(series.buckets.is_empty());
+    }
