+    #[test]
+    fn throughput_gap_filling() {
+        let ring = Arc::new(EventRingBuffer::with_capacity(100));
+        // Events 3 seconds apart should create gap-filled zero buckets
+        ring.push(tool_call_end_at(1_000_000, 10));
